@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;500;600;700;800&family=Fraunces:opsz,wght@9..144,600;9..144,700&display=swap');

:root {
  color-scheme: dark;
  --xana-reader-scale: 1;
  --xana-bg: #05070a;
  --xana-surface: #111827;
  --xana-surface-elevated: #151922;
  --xana-panel-bg: rgba(14, 18, 26, 0.96);
  --xana-panel-border: rgba(255, 255, 255, 0.08);
  --xana-text: #f8fafc;
  --xana-text-muted: #94a3b8;
  --xana-accent: #55d6be;
  --xana-accent-soft: rgba(85, 214, 190, 0.14);
  --xana-accent-border: rgba(85, 214, 190, 0.26);
  --xana-scrollbar-track: rgba(10, 14, 19, 0.9);
  --xana-scrollbar-thumb: var(--xana-accent);
  --xana-scrollbar-thumb-hover: #f8fafc;
  --xana-section-people: #8bd3ff;
  --xana-section-people-soft: rgba(139, 211, 255, 0.15);
  --xana-section-people-border: rgba(139, 211, 255, 0.28);
  --xana-section-claims: #ff6b6b;
  --xana-section-claims-soft: rgba(255, 107, 107, 0.12);
  --xana-section-claims-border: rgba(255, 107, 107, 0.3);
  --xana-section-projects: #ffd166;
  --xana-section-projects-soft: rgba(255, 209, 102, 0.14);
  --xana-section-projects-border: rgba(255, 209, 102, 0.28);
  --xana-section-sources: #ff9f7a;
  --xana-section-sources-soft: rgba(255, 159, 122, 0.14);
  --xana-section-sources-border: rgba(255, 159, 122, 0.28);
  --xana-section-media: #55d6be;
  --xana-section-media-soft: rgba(85, 214, 190, 0.12);
  --xana-section-media-border: rgba(85, 214, 190, 0.3);
  --xana-section-observations: #ef476f;
  --xana-section-observations-soft: rgba(239, 71, 111, 0.12);
  --xana-section-observations-border: rgba(239, 71, 111, 0.3);
  --xana-section-concepts: #91f2a6;
  --xana-section-concepts-soft: rgba(145, 242, 166, 0.14);
  --xana-section-concepts-border: rgba(145, 242, 166, 0.26);
  --xana-section-essays: #f59ec3;
  --xana-section-essays-soft: rgba(245, 158, 195, 0.14);
  --xana-section-essays-border: rgba(245, 158, 195, 0.28);
  --xana-section-events: #f59e0b;
  --xana-section-events-soft: rgba(245, 158, 11, 0.12);
  --xana-section-events-border: rgba(245, 158, 11, 0.3);
  --xana-section-place: #84cc16;
  --xana-section-place-soft: rgba(132, 204, 22, 0.12);
  --xana-section-place-border: rgba(132, 204, 22, 0.3);
  --xana-section-technologies: #06b6d4;
  --xana-section-technologies-soft: rgba(6, 182, 212, 0.12);
  --xana-section-technologies-border: rgba(6, 182, 212, 0.3);
  --xana-section-organizations: #f0abfc;
  --xana-section-organizations-soft: rgba(240, 171, 252, 0.12);
  --xana-section-organizations-border: rgba(240, 171, 252, 0.3);
  --xana-section-trails: #fb8500;
  --xana-section-trails-soft: rgba(251, 133, 0, 0.12);
  --xana-section-trails-border: rgba(251, 133, 0, 0.3);
}

html[data-xana-theme="light"] {
  color-scheme: light;
  --xana-bg: #f3f7fb;
  --xana-surface: #ffffff;
  --xana-surface-elevated: #f1f5f9;
  --xana-panel-bg: rgba(255, 255, 255, 0.985);
  --xana-panel-border: rgba(30, 41, 59, 0.18);
  --xana-text: #0f172a;
  --xana-text-muted: #475569;
  --xana-accent: #0f766e;
  --xana-accent-soft: rgba(15, 118, 110, 0.12);
  --xana-accent-border: rgba(15, 118, 110, 0.28);
  --xana-scrollbar-track: rgba(226, 232, 240, 0.95);
  --xana-scrollbar-thumb: #64748b;
  --xana-scrollbar-thumb-hover: #0f766e;
}

html[data-xana-theme="classic"] {
  color-scheme: light;
  --xana-bg: #f8f9fa;
  --xana-surface: #ffffff;
  --xana-surface-elevated: #f6f6f6;
  --xana-panel-bg: #ffffff;
  --xana-panel-border: #a2a9b1;
  --xana-text: #202122;
  --xana-text-muted: #54595d;
  --xana-accent: #3366cc;
  --xana-accent-soft: rgba(51, 102, 204, 0.1);
  --xana-accent-border: rgba(51, 102, 204, 0.35);
  --xana-scrollbar-track: #eaecf0;
  --xana-scrollbar-thumb: #a2a9b1;
  --xana-scrollbar-thumb-hover: #3366cc;
}

html[data-xana-theme="accessible"] {
  color-scheme: dark;
  --xana-bg: #000000;
  --xana-surface: #0b0f14;
  --xana-surface-elevated: #111827;
  --xana-panel-bg: rgba(0, 0, 0, 0.98);
  --xana-panel-border: rgba(255, 255, 255, 0.32);
  --xana-text: #ffffff;
  --xana-text-muted: #d1d5db;
  --xana-accent: #f0e442;
  --xana-accent-soft: rgba(240, 228, 66, 0.16);
  --xana-accent-border: rgba(240, 228, 66, 0.55);
  --xana-scrollbar-track: #111827;
  --xana-scrollbar-thumb: #f0e442;
  --xana-scrollbar-thumb-hover: #ffffff;
  --xana-section-people: #56b4e9;
  --xana-section-people-soft: rgba(86, 180, 233, 0.18);
  --xana-section-people-border: rgba(86, 180, 233, 0.48);
  --xana-section-claims: #d55e00;
  --xana-section-claims-soft: rgba(213, 94, 0, 0.18);
  --xana-section-claims-border: rgba(213, 94, 0, 0.5);
  --xana-section-projects: #0072b2;
  --xana-section-projects-soft: rgba(0, 114, 178, 0.22);
  --xana-section-projects-border: rgba(0, 114, 178, 0.5);
  --xana-section-sources: #e69f00;
  --xana-section-sources-soft: rgba(230, 159, 0, 0.18);
  --xana-section-sources-border: rgba(230, 159, 0, 0.5);
  --xana-section-media: #56b4e9;
  --xana-section-media-soft: rgba(86, 180, 233, 0.18);
  --xana-section-media-border: rgba(86, 180, 233, 0.48);
  --xana-section-observations: #cc79a7;
  --xana-section-observations-soft: rgba(204, 121, 167, 0.2);
  --xana-section-observations-border: rgba(204, 121, 167, 0.5);
  --xana-section-concepts: #009e73;
  --xana-section-concepts-soft: rgba(0, 158, 115, 0.2);
  --xana-section-concepts-border: rgba(0, 158, 115, 0.5);
  --xana-section-essays: #cc79a7;
  --xana-section-essays-soft: rgba(204, 121, 167, 0.2);
  --xana-section-essays-border: rgba(204, 121, 167, 0.5);
  --xana-section-events: #e69f00;
  --xana-section-events-soft: rgba(230, 159, 0, 0.18);
  --xana-section-events-border: rgba(230, 159, 0, 0.5);
  --xana-section-place: #009e73;
  --xana-section-place-soft: rgba(0, 158, 115, 0.2);
  --xana-section-place-border: rgba(0, 158, 115, 0.5);
  --xana-section-technologies: #0072b2;
  --xana-section-technologies-soft: rgba(0, 114, 178, 0.22);
  --xana-section-technologies-border: rgba(0, 114, 178, 0.5);
  --xana-section-organizations: #cc79a7;
  --xana-section-organizations-soft: rgba(204, 121, 167, 0.2);
  --xana-section-organizations-border: rgba(204, 121, 167, 0.5);
  --xana-section-trails: #f0e442;
  --xana-section-trails-soft: rgba(240, 228, 66, 0.16);
  --xana-section-trails-border: rgba(240, 228, 66, 0.55);
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  overflow: hidden;
  background: var(--xana-bg);
  color: var(--xana-text);
  font-family: 'IBM Plex Sans', 'Segoe UI', sans-serif;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

html[data-xana-theme="classic"] body {
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
}

html[data-xana-theme="classic"] h1,
html[data-xana-theme="classic"] h2,
html[data-xana-theme="classic"] h3,
html[data-xana-theme="classic"] h4,
html[data-xana-theme="classic"] h5,
html[data-xana-theme="classic"] h6 {
  font-family: Georgia, "Times New Roman", serif;
  letter-spacing: 0;
}

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: 'Fraunces', Georgia, serif;
  font-weight: 700;
  letter-spacing: -0.02em;
}

p,
li,
td,
dd,
input,
button {
  font-family: inherit;
}

a:focus-visible,
button:focus-visible,
input:focus-visible,
select:focus-visible,
summary:focus-visible {
  outline: 2px solid var(--xana-accent);
  outline-offset: 3px;
}

.site-header,
.site-nav {
  display: none !important;
}

.site-main {
  max-width: none !important;
  width: 100vw;
  height: 100vh;
  padding: 0 !important;
  margin: 0 !important;
}

.xana-app {
  height: 100vh;
  width: 100vw;
  display: grid;
  grid-template-columns: minmax(360px, 1fr) 8px minmax(340px, 520px);
  grid-template-rows: 52px 1fr;
  background: var(--xana-bg);
  color: var(--xana-text);
  overflow: hidden;
}

.xana-resizer {
  width: 8px;
  cursor: col-resize;
  background: var(--xana-surface);
  border-left: 1px solid #2c3442;
  border-right: 1px solid #2c3442;
  z-index: 15;
}

.xana-resizer:hover,
body.is-resizing .xana-resizer {
  background: var(--xana-accent);
}

body.is-resizing {
  user-select: none;
  cursor: col-resize;
}

#xana-graph {
  --xana-controls-height: 64px;
  min-width: 0;
  height: 100%;
  width: 100%;
  overflow: hidden;
  position: relative;
  background:
    radial-gradient(circle at 35% 30%, var(--xana-accent-soft), transparent 30%),
    radial-gradient(circle at 75% 70%, rgba(255, 209, 102, 0.1), transparent 25%),
    var(--xana-bg);
}

#xana-stage {
  position: absolute;
  left: 0;
  right: 0;
  top: 0;
  bottom: var(--xana-controls-height);
  height: auto;
  width: 100%;
  z-index: 1;
}

.xana-graph-svg {
  display: block;
  width: 100%;
  height: 100%;
  user-select: none;
  touch-action: none;
}

.graph-surface {
  fill: #05070a;
}

.graph-layer {
  will-change: transform;
}

.graph-travel-layer {
  pointer-events: none;
}

.graph-edge path {
  fill: none;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.graph-edge polygon {
  transform-box: fill-box;
  transform-origin: center;
}

.graph-edge-label {
  fill: #e2e8f0;
  font-family: 'IBM Plex Sans', 'Segoe UI', sans-serif;
  font-size: 12px;
  font-weight: 700;
  text-anchor: middle;
  paint-order: stroke;
  stroke: rgba(5, 7, 10, 0.92);
  stroke-width: 4.5px;
}

.graph-node {
  cursor: pointer;
}

.graph-node.dragging {
  cursor: grabbing;
}

.graph-node.dragging circle {
  filter: drop-shadow(0 0 18px rgba(85, 214, 190, 0.45));
}

.graph-node circle {
  vector-effect: non-scaling-stroke;
}

.graph-node text {
  font-family: 'IBM Plex Sans', 'Segoe UI', sans-serif;
  font-size: 14.5px;
  font-weight: 800;
  text-anchor: middle;
  paint-order: stroke;
  stroke: rgba(5, 7, 10, 0.9);
  stroke-width: 2.6px;
  pointer-events: none;
}

.graph-node-title-chip rect {
  fill: rgba(5, 10, 18, 0.94);
  stroke: rgba(148, 163, 184, 0.48);
  stroke-width: 1.4;
  vector-effect: non-scaling-stroke;
}

.graph-node-title {
  font-size: 13px;
  font-weight: 850;
  fill: #f8fafc;
  paint-order: stroke;
  stroke: rgba(0, 0, 0, 0.82);
  stroke-width: 2.2px;
}

.graph-node-icon {
  font-size: 18px;
  font-weight: 900;
  paint-order: stroke;
  stroke: rgba(255, 255, 255, 0.18);
  stroke-width: 1.2px;
  pointer-events: none;
}

.graph-node.selected .graph-node-icon {
  font-size: 22px;
}

.graph-node-media {
  pointer-events: none;
  opacity: 0.96;
}

.graph-node-type-media {
  pointer-events: none;
  opacity: 0.96;
}

.graph-type-badge rect {
  fill: rgba(2, 8, 13, 0.7);
  stroke: rgba(85, 214, 190, 0.42);
  stroke-width: 1.1;
  vector-effect: non-scaling-stroke;
}

.graph-type {
  fill: rgba(159, 247, 232, 0.86);
  paint-order: stroke;
  stroke: rgba(0, 0, 0, 0.68);
  stroke-width: 1.4px;
  font-size: 8.5px;
}

.graph-node .graph-type {
  font-size: 10px;
  font-weight: 900;
  letter-spacing: 0.03em;
  text-transform: uppercase;
  stroke-width: 1.8px;
}

.graph-node.selected text {
  font-size: 14px;
}

.graph-node.selected .graph-node-title {
  font-size: 14.5px;
}

.graph-node.distance-1 .graph-node-title {
  font-size: 13px;
}

.graph-node.distance-2 .graph-node-title,
.graph-node.distance-3 .graph-node-title,
.graph-node.distance-4 .graph-node-title {
  font-size: 12px;
}

.graph-node.distance-3 .graph-type-badge,
.graph-node.distance-4 .graph-type-badge {
  display: none;
}

.graph-node.selected circle {
  filter: drop-shadow(0 0 16px rgba(85, 214, 190, 0.35));
}

.xana-graph-svg.is-staged .graph-node,
.xana-graph-svg.is-staged .graph-edge {
  opacity: 0;
  animation: graph-depth-reveal 520ms cubic-bezier(0.2, 0.85, 0.25, 1) forwards;
  animation-delay: var(--reveal-delay, 0ms);
}

.xana-graph-svg.is-staged .graph-node.selected {
  animation-duration: 280ms;
}

@keyframes graph-depth-reveal {
  from {
    opacity: 0;
    filter: blur(2px);
  }
  to {
    opacity: var(--graph-depth-opacity, 1);
    filter: blur(0);
  }
}

.xana-graph-caption {
  position: absolute;
  right: 20px;
  bottom: 12px;
  color: var(--xana-text-muted);
  font-size: 12px;
  z-index: 2;
  pointer-events: none;
}

.graph-travel-rail {
  stroke: rgba(85, 214, 190, 0.92);
  stroke-width: 4;
  stroke-linecap: round;
  stroke-dasharray: 10 8;
  filter: drop-shadow(0 0 10px rgba(85, 214, 190, 0.35));
  opacity: 0;
  animation: graph-travel-rail 620ms ease-out var(--travel-delay, 0ms) forwards;
}

.graph-travel-start {
  fill: rgba(255, 255, 255, 0.95);
  stroke: rgba(85, 214, 190, 0.95);
  stroke-width: 2;
}

.graph-travel-step {
  fill: rgba(85, 214, 190, 0.95);
  stroke: rgba(255, 255, 255, 0.9);
  stroke-width: 2;
  opacity: 0;
  transform-box: fill-box;
  transform-origin: center;
  animation: graph-travel-step 360ms ease-out var(--travel-delay, 0ms) forwards;
}

@keyframes graph-travel-rail {
  from {
    stroke-dashoffset: 112;
    opacity: 0;
  }
  to {
    stroke-dashoffset: 0;
    opacity: 0.96;
  }
}

@keyframes graph-travel-step {
  from {
    transform: scale(0.58);
    opacity: 0;
  }
  to {
    transform: scale(1);
    opacity: 0.96;
  }
}

.xana-graph-atmosphere {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  overflow: hidden;
  background:
    radial-gradient(circle at 18% 22%, rgba(85, 214, 190, 0.16), transparent 26%),
    radial-gradient(circle at 78% 68%, rgba(255, 209, 102, 0.12), transparent 22%),
    linear-gradient(135deg, rgba(85, 214, 190, 0.05), transparent 45%);
}

.xana-graph-atmosphere::before,
.xana-graph-atmosphere::after {
  content: "";
  position: absolute;
  inset: -20%;
  opacity: 0.55;
  background-image:
    radial-gradient(circle, rgba(255, 255, 255, 0.18) 0 1px, transparent 1px),
    radial-gradient(circle, rgba(85, 214, 190, 0.18) 0 1px, transparent 1px);
  background-size: 58px 58px, 92px 92px;
  animation: xana-info-current 38s linear infinite;
}

.xana-graph-atmosphere::after {
  opacity: 0.28;
  filter: blur(1px);
  animation-duration: 64s;
  animation-direction: reverse;
}

@keyframes xana-info-current {
  from { transform: translate3d(0, 0, 0) rotate(0deg); }
  to { transform: translate3d(-58px, -34px, 0) rotate(1deg); }
}

html[data-xana-atmosphere="still"] .xana-graph-atmosphere::before,
html[data-xana-atmosphere="still"] .xana-graph-atmosphere::after {
  animation: none;
}

html[data-xana-atmosphere="plain"] .xana-graph-atmosphere {
  display: none;
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    scroll-behavior: auto !important;
    transition-duration: 0.001ms !important;
    animation-duration: 0.001ms !important;
    animation-iteration-count: 1 !important;
  }

  .xana-graph-atmosphere::before,
  .xana-graph-atmosphere::after {
    animation: none;
  }
}

html,
body,
.xana-panel,
.xana-search-results,
.xana-filter-popover-body,
.xana-list-page,
#xana-audit-stage {
  scrollbar-width: thin;
  scrollbar-color: var(--xana-scrollbar-thumb) var(--xana-scrollbar-track);
}

*::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

*::-webkit-scrollbar-track {
  background: var(--xana-scrollbar-track);
}

*::-webkit-scrollbar-thumb {
  background: var(--xana-scrollbar-thumb);
  border-radius: 999px;
  border: 2px solid var(--xana-scrollbar-track);
}

*::-webkit-scrollbar-thumb:hover {
  background: var(--xana-scrollbar-thumb-hover);
}

/* ── Navbar ─────────────────────────────────────────────────────────────── */

.xana-navbar {
  grid-column: 1 / -1;
  grid-row: 1;
  display: flex;
  align-items: center;
  padding: 0 1.25rem;
  background: rgba(5, 7, 10, 0.96);
  border-bottom: 1px solid rgba(255, 255, 255, 0.07);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  z-index: 20;
  gap: 1rem;
}

/* ── Brand (lives inside navbar) ────────────────────────────────────────── */

.xana-brand-home {
  display: flex;
  align-items: center;
  gap: 0.55rem;
  padding: 0.3rem 0.7rem 0.3rem 0.3rem;
  border-radius: 0.75rem;
  background: transparent;
  border: 1px solid transparent;
  cursor: pointer;
  flex-shrink: 0;
  transition: border-color 150ms, background 150ms;
}

.xana-brand-home:hover {
  border-color: rgba(85, 214, 190, 0.35);
  background: rgba(255, 255, 255, 0.05);
}

.xana-brand-icon {
  width: 28px;
  height: 28px;
  border-radius: 6px;
  display: block;
  object-fit: contain;
}

.xana-brand-text {
  display: flex;
  flex-direction: column;
  gap: 0.05rem;
  text-align: left;
}

.xana-brand-name {
  font-size: 0.82rem;
  font-weight: 900;
  color: #f8fafc;
  letter-spacing: 0.03em;
  line-height: 1.15;
}

.xana-brand-tagline {
  font-size: 0.57rem;
  color: #55d6be;
  font-weight: 600;
  letter-spacing: 0.05em;
  opacity: 0.8;
  line-height: 1.2;
}

/* ── Attribution watermark ──────────────────────────────────────────────── */

.xana-attribution {
  position: absolute;
  bottom: 0.9rem;
  right: 1rem;
  z-index: 31;
  font-size: 0.6rem;
  color: rgba(148, 163, 184, 0.45);
  pointer-events: none;
  user-select: none;
  letter-spacing: 0.03em;
}

.xana-attribution a {
  color: rgba(85, 214, 190, 0.55);
  text-decoration: none;
  pointer-events: all;
}

.xana-attribution a:hover {
  color: #55d6be;
}

.xana-attribution-home {
  background: none;
  border: none;
  padding: 0;
  margin: 0;
  font: inherit;
  font-size: inherit;
  color: rgba(148, 163, 184, 0.55);
  pointer-events: all;
  cursor: pointer;
  text-decoration: none;
  transition: color 150ms;
}

.xana-attribution-home:hover {
  color: #55d6be;
}

/* ── Search portal ──────────────────────────────────────────────────────── */

.xana-searcher {
  position: absolute;
  top: 1.25rem;
  left: 50%;
  transform: translateX(-50%);
  z-index: 30;
  width: clamp(280px, 56%, 520px);
  pointer-events: auto;
}

.xana-search-wrap {
  display: block;
  position: relative;
  background: rgba(5, 7, 10, 0.82);
  border: 1px solid rgba(255, 255, 255, 0.13);
  border-radius: 1.5rem;
  padding: 0.55rem 0.6rem 0.55rem 1rem;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.4);
  backdrop-filter: blur(20px);
  transition: border-color 200ms ease, box-shadow 200ms ease;
}

.xana-search-wrap:focus-within {
  border-color: rgba(85, 214, 190, 0.5);
