/* ── Tour countdown ring ─────────────────────────────────────────────────── */

/* Register the custom angle property so conic-gradient can be animated */
@property --tour-p {
  syntax: "<angle>";
  initial-value: 0deg;
  inherits: false;
}

@keyframes tour-ring {
  from { --tour-p: 0deg; }
  to   { --tour-p: 360deg; }
}

.xana-ctrl-btn[data-tour-toggle] {
  /* needs a stacking context for the ::before ring */
  position: relative;
}

.xana-ctrl-btn[data-tour-toggle].tour-ring-anim::before {
  content: "";
  position: absolute;
  inset: -3px;
  border-radius: 0.85rem; /* slightly larger than button's 0.65rem to clear it */
  padding: 3px;           /* ring thickness */
  background: conic-gradient(#55d6be var(--tour-p), rgba(85, 214, 190, 0.12) 0deg);
  /* mask trick: show only the padding band, not the content area */
  -webkit-mask:
    linear-gradient(#fff 0 0) content-box,
    linear-gradient(#fff 0 0);
  mask:
    linear-gradient(#fff 0 0) content-box,
    linear-gradient(#fff 0 0);
  -webkit-mask-composite: destination-out;
  mask-composite: exclude;
  animation: tour-ring var(--tour-dur, 9s) linear forwards;
  z-index: -1;
  pointer-events: none;
}

/* ── Tour speed input ────────────────────────────────────────────────────── */

