        "year": {{ ($p.Params.year | default "") | jsonify }}
      }
    {{- end }}
  ],
  "edges": [
    {{- $first := true -}}
    {{- range $p := $pages -}}
      {{- $source := $p.Params.node_id | default $p.File.ContentBaseName -}}

      {{- with $p.Params.primary_media -}}
        {{- if not $first }},{{ end -}}{{- $first = false -}}
        {
          "source": {{ $source | jsonify }},
