    <p class="xana-inline-type">
      {{ $target.Params.node_type | default $target.Params.type | default $target.Section }}
    </p>
    <h3>
      <a href="{{ $target.RelPermalink }}">{{ $target.Title }}</a>
    </h3>
    {{ with $target.Params.summary }}
      <p>{{ . }}</p>
    {{ end }}
  </div>
{{ else }}
  <div class="xana-inline-node missing">
    <p>Missing node: {{ $id }}</p>
  </div>
{{ end }}

{{ $type := .Get "type" }}
{{ $targetID := .Get "target" }}
{{ $target := partial "find-page-by-id.html" $targetID }}
<span class="inline-relation"><span class="relation-type">{{ $type }}</span>{{ if $target }}<a href="{{ $target.RelPermalink }}">{{ $target.Title }}</a>{{ else }}{{ $targetID }}{{ end }}</span>

{{ $sourceID := .Get "source" }}
{{ $label := .Get "label" }}
{{ $sourcePage := site.GetPage (printf "/sources/%s" $sourceID) }}
<aside class="transclusion">
  <div class="transclusion-label">{{ if $label }}{{ $label }}{{ else }}Transcluded source{{ end }}</div>
  {{ if $sourcePage }}
    <h3><a href="{{ $sourcePage.RelPermalink }}">{{ $sourcePage.Title }}</a></h3>
    <dl class="source-details">
      {{ with $sourcePage.Params.author }}<dt>Author</dt><dd>{{ . }}</dd>{{ end }}
      {{ with $sourcePage.Params.year }}<dt>Year</dt><dd>{{ . }}</dd>{{ end }}
      {{ with $sourcePage.Params.source_url }}<dt>Original</dt><dd><a href="{{ . }}">Source link</a></dd>{{ end }}
      {{ with $sourcePage.Params.archive_url }}<dt>Archive</dt><dd><a href="{{ . }}">Archived link</a></dd>{{ end }}
    </dl>
    {{ with $sourcePage.Params.summary }}<p>{{ . }}</p>{{ else }}{{ with $sourcePage.Summary }}<p>{{ . }}</p>{{ end }}{{ end }}
  {{ else }}
    <p>Missing source node: <code>{{ $sourceID }}</code></p>
  {{ end }}
</aside>

{{- $ref := .Get "ref" -}}
{{- $label := .Get "label" -}}
{{- $parts := split (replaceRE "^xana://" "" $ref) "/" -}}
{{- $nodeVersion := index $parts 0 -}}
{{- $range := cond (ge (len $parts) 2) (index $parts 1) "1" -}}
{{- $nodeParts := split $nodeVersion "@" -}}
{{- $nodeID := index $nodeParts 0 -}}
{{- $version := cond (ge (len $nodeParts) 2) (index $nodeParts 1) "latest" -}}
{{- $nodeData := index site.Data.xananode_fragments.nodes $nodeID -}}
{{- $page := partial "find-page-by-id.html" (dict "id" $nodeID) -}}
<aside class="transclusion xana-transclusion" id="xana-ref-{{ $nodeID | urlize }}-{{ $version | urlize }}-{{ $range | urlize }}" data-xana-ref="{{ $ref }}" data-xana-node="{{ $nodeID }}" data-xana-version="{{ $version }}" data-xana-range="{{ $range }}">
  <div class="transclusion-label" data-tts-skip="">{{ if $label }}{{ $label }}{{ else }}Xana transclusion{{ end }}</div>
  {{- if $nodeData -}}
    {{- $versionData := index $nodeData.versions $version -}}
    {{- if not $versionData }}{{ $versionData = index $nodeData.versions "latest" }}{{ end -}}
    {{- $text := "" -}}
    {{- $meta := false -}}
    {{- if $versionData -}}
      {{- $text = index $versionData.fragments $range -}}
      {{- $meta = index $versionData.metadata $range -}}
    {{- end -}}
    {{- if $text -}}
      <blockquote data-xana-transclusion-text="true">{{ $text | markdownify }}</blockquote>
      <p class="xana-transclusion-citation" data-tts-skip="">
        {{ if $page -}}
          <a class="xana-transclusion-source" href="{{ $page.RelPermalink }}" data-node-jump="{{ $nodeID }}" title="Transcluded from {{ $page.Title }} fragment {{ if $meta }}{{ $meta.id }}{{ else }}{{ $range }}{{ end }}" aria-label="Transcluded from {{ $page.Title }} fragment {{ if $meta }}{{ $meta.id }}{{ else }}{{ $range }}{{ end }}">source</a>
        {{ else -}}
          <span class="xana-transclusion-source" title="Transcluded from {{ $nodeData.title }} fragment {{ if $meta }}{{ $meta.id }}{{ else }}{{ $range }}{{ end }}" aria-label="Transcluded from {{ $nodeData.title }} fragment {{ if $meta }}{{ $meta.id }}{{ else }}{{ $range }}{{ end }}">source</span>
        {{ end -}}
      </p>
      <details class="xana-transclusion-details" data-tts-skip="">
        <summary>Reference details</summary>
        <dl class="xana-transclusion-meta">
          <div>
            <dt>Version</dt>
            <dd><code>{{ $version }}</code></dd>
          </div>
          <div>
            <dt>Address</dt>
            <dd><code>{{ if $meta }}{{ $meta.tumbler }}{{ else }}{{ $ref }}{{ end }}</code></dd>
          </div>
          {{- if and $meta $meta.selector -}}
            <div>
              <dt>Selector</dt>
              <dd><code>{{ $meta.selector.type }}:{{ $meta.selector.value }}</code></dd>
            </div>
          {{- end -}}
        </dl>
      </details>
    {{- else -}}
      <p>Fragment not found for range <code>{{ $range }}</code>. Run <code>npm run prepare</code> to regenerate fragment data.</p>
    {{- end -}}
  {{- else -}}
    <p>Missing XanaNode reference: <code>{{ $ref }}</code></p>
  {{- end -}}
</aside>

