import fs from "node:fs";
import path from "node:path";
import crypto from "node:crypto";
import { spawnSync } from "node:child_process";
import { fileURLToPath } from "node:url";

const hugoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const defaultOutDir = path.join(hugoRoot, "substrate-source");
const generatedAt = new Date().toISOString();

const includeRoots = new Set([".github", "archetypes", "assets", "exampleSite", "layouts", "static", "tools"]);
const includeRootFiles = new Set(["README.md", "LICENSE", "package.json", "package-lock.json", ".gitmodules", ".gitignore", "hugo.yaml", "theme.toml"]);
const includeExtensions = new Set([".js", ".json", ".md", ".txt", ".mjs", ".yaml", ".toml", ".html", ".css", ".svg", ".png", ".ico", ""]);

function gitValue(args) {
  const result = spawnSync("git", args, { cwd: hugoRoot, encoding: "utf8", shell: false });
  return result.status === 0 ? result.stdout.trim() : "";
}

function readPackageVersion() {
  try {
    return JSON.parse(fs.readFileSync(path.join(hugoRoot, "package.json"), "utf8")).version || "0.1.0";
  } catch {
    return "0.1.0";
  }
}

function slug(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function writeJson(filePath, value) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, `${JSON.stringify(value, null, 2)}\n`);
}

function writeText(filePath, value) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, value);
}

function cleanDir(dir) {
  if (!fs.existsSync(dir)) return;
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    fs.rmSync(path.join(dir, entry.name), { recursive: true, force: true, maxRetries: 5, retryDelay: 50 });
  }
}

function sha256File(filePath) {
  const hash = crypto.createHash("sha256");
  hash.update(fs.readFileSync(filePath));
  return `sha256:${hash.digest("hex")}`;
}

function safeAssetRelativePath(relativePath) {
  return String(relativePath || "").replace(/\\/g, "/").replace(/^\.\//, "").replace(/\.\./g, "_");
}

function sourceUrl(relativePath) {
  return `https://github.com/kingc95/XanaNode-Hugo/blob/main/${safeAssetRelativePath(relativePath)}`;
}

function mimeTypeFor(relativePath) {
  const ext = path.extname(relativePath).toLowerCase();
  if (ext === ".json") return "application/json";
  if (ext === ".html") return "text/html";
  if (ext === ".css") return "text/css";
  if (ext === ".svg") return "image/svg+xml";
  if (ext === ".png") return "image/png";
  if (ext === ".ico") return "image/x-icon";
  return "text/plain";
}

function nodeKindFor(relativePath) {
  const clean = safeAssetRelativePath(relativePath);
  const ext = path.extname(clean).toLowerCase();
  if (clean.startsWith("assets/") || clean.startsWith("static/")) {
    const isImage = [".svg", ".png", ".ico"].includes(ext);
    return {
      type: isImage ? "media" : "source",
      subtype: isImage ? "projection_asset" : "renderer_asset",
      media_type: isImage ? "image" : "document",
      mime_type: mimeTypeFor(clean)
    };
  }
  if (clean.startsWith("layouts/") || clean.startsWith("tools/") || clean.startsWith("archetypes/")) {
    return {
      type: "source",
      subtype: "reference_code",
      media_type: "document",
      mime_type: mimeTypeFor(clean)
    };
  }
  if (clean.startsWith("exampleSite/")) {
    return {
      type: "source",
      subtype: "example_substrate_projection",
      media_type: "document",
      mime_type: mimeTypeFor(clean)
    };
  }
  return {
    type: "source",
    subtype: "project_document",
    media_type: "document",
    mime_type: mimeTypeFor(clean)
  };
}

function titleFor(relativePath) {
  const clean = safeAssetRelativePath(relativePath);
  if (clean === "README.md") return "XanaNode Hugo Theme README";
  if (clean === "package.json") return "XanaNode Hugo Theme Package Manifest";
  if (clean === "hugo.yaml") return "XanaNode Hugo Theme Configuration";
  if (clean === "theme.toml") return "XanaNode Hugo Theme Definition";
  return clean
    .replace(/\.[^.]+$/, "")
    .split("/")
    .filter(Boolean)
    .map((part) => part.replace(/[-_]+/g, " ").replace(/\b\w/g, (c) => c.toUpperCase()))
    .join(" / ");
}

function summaryFor(relativePath, kind) {
  const clean = safeAssetRelativePath(relativePath);
  if (kind.type === "media") return `${clean} is preserved as a Hugo projection or branding asset in the XanaNode Hugo substrate.`;
  return `${clean} is preserved as a raw Hugo source artifact in the XanaNode Hugo substrate.`;
}

function listRepositoryFiles() {
  const files = [];
  function visit(current) {
    for (const entry of fs.readdirSync(current, { withFileTypes: true })) {
      if (entry.name === "node_modules" || entry.name === "substrate-source" || entry.name === ".hugo_build.lock" || entry.name.startsWith(".git")) continue;
      const fullPath = path.join(current, entry.name);
      const relativePath = path.relative(hugoRoot, fullPath).replace(/\\/g, "/");
      if (
        relativePath.startsWith("exampleSite/public/") ||
        relativePath === "exampleSite/public" ||
        relativePath.startsWith("exampleSite/resources/") ||
        relativePath === "exampleSite/resources" ||
        relativePath.startsWith("exampleSite/static/") ||
        relativePath === "exampleSite/static" ||
        relativePath === "exampleSite/.hugo_build.lock"
      ) {
        continue;
      }
      const top = relativePath.split("/")[0];
      if (entry.isDirectory()) {
        if (includeRoots.has(top)) visit(fullPath);
        continue;
      }
      if (!entry.isFile()) continue;
      const ext = path.extname(entry.name).toLowerCase();
      if (!includeRootFiles.has(relativePath) && !includeRoots.has(top)) continue;
      if (!includeExtensions.has(ext) && !includeRootFiles.has(relativePath)) continue;
      files.push(relativePath);
    }
  }
  visit(hugoRoot);
  return files.sort((a, b) => a.localeCompare(b));
}

function readTextIfPossible(filePath) {
  const ext = path.extname(filePath).toLowerCase();
  if (![".js", ".json", ".md", ".txt", ".mjs", ".yaml", ".toml", ".html", ".css", ""].includes(ext)) return "";
  try {
    return fs.readFileSync(filePath, "utf8");
  } catch {
    return "";
  }
}

export function buildHugoSubstrateSource(outDir = defaultOutDir) {
  cleanDir(outDir);
  const version = readPackageVersion();

  const manifest = {
    id: "xananode.hugo",
    name: "XanaNode Hugo Theme Substrate",
    version,
    namespace: "xananode.hugo",
    description: "A substrate source built directly from the XanaNode Hugo repository, preserving the Hugo theme, static viewer assets, example site, layouts, build glue, and projection-facing documents as first-class XanaNode records.",
    schema_version: "xananode-core@0.5.0",
    repository: {
      type: "git",
      url: "https://github.com/kingc95/XanaNode-Hugo.git",
      default_branch: "main"
    },
    imports: ["xananode.core"],
    build_metadata: {
      built_at: generatedAt,
      git_commit: gitValue(["rev-parse", "HEAD"]),
      git_branch: gitValue(["rev-parse", "--abbrev-ref", "HEAD"]),
      built_by: "xananode-hugo/tools/build-substrate-source.mjs"
    },
    sharing: {
      default_shareable: true,
      rules: [
        {
          selector: { namespace: "xananode.hugo" },
          shareable: true,
          scope: "public",
          reason: "The Hugo substrate is intended to be federated as a public projection implementation source."
        }
      ]
    }
  };

  const nodes = [
    {
      id: "xananode.hugo:project/xananode-hugo-theme",
      title: "XanaNode Hugo Theme",
      type: "project",
      subtype: "projection_layer",
      importance: 5,
      summary: "The Hugo-based projection layer that renders XanaNode substrates as readable pages, protocol artifacts, and a navigable graph.",
      source_url: "https://github.com/kingc95/XanaNode-Hugo",
      repository: "kingc95/XanaNode-Hugo",
      software_version: version,
      relationships: []
    },
    {
      id: "xananode.hugo:source/repository-xananode-hugo",
      title: "XanaNode Hugo Repository",
      type: "source",
      subtype: "git_repository",
      importance: 5,
      summary: "Public Git repository for the XanaNode Hugo theme and read-only substrate viewer.",
      source_url: "https://github.com/kingc95/XanaNode-Hugo",
      repository: "kingc95/XanaNode-Hugo",
      rights_status: "external",
      relationships: []
    },
    {
      id: "xananode.hugo:technology/xananode-hugo-renderer",
      title: "XanaNode Hugo Renderer",
      type: "technology",
      subtype: "static_site_renderer",
      importance: 4,
      summary: "The static-site rendering surface that projects XanaNode substrates into HTML, machine discovery endpoints, and a graph-driven reading experience.",
      software_version: version,
      relationships: []
    }
  ];

  const relationships = [
    {
      id: "xananode.hugo:rel/repository-documents-hugo-project",
      source: "xananode.hugo:source/repository-xananode-hugo",
      target: "xananode.hugo:project/xananode-hugo-theme",
      type: "documents",
      summary: "The repository documents and carries the Hugo theme project.",
      asserted_at: generatedAt
    },
    {
      id: "xananode.hugo:rel/hugo-project-implements-core",
      source: "xananode.hugo:project/xananode-hugo-theme",
      target: "xananode.core:project/xananode-core-sdk",
      type: "implements",
      summary: "The Hugo theme uses Core as its validation and protocol-artifact engine.",
      asserted_at: generatedAt
    },
    {
      id: "xananode.hugo:rel/hugo-renderer-supports-hugo-project",
      source: "xananode.hugo:technology/xananode-hugo-renderer",
      target: "xananode.hugo:project/xananode-hugo-theme",
      type: "supports",
      summary: "The renderer is the human-facing projection surface of the Hugo theme.",
      asserted_at: generatedAt
    }
  ];

  for (const relativePath of listRepositoryFiles()) {
    const sourcePath = path.join(hugoRoot, relativePath);
    const kind = nodeKindFor(relativePath);
    const localSlug = slug(relativePath.replace(/\.[^.]+$/, "")) || "artifact";
    const nodeId = `xananode.hugo:${kind.type}/artifact-${localSlug}`;
    const assetPath = `assets/raw/repository/${safeAssetRelativePath(relativePath)}`;
    const assetTarget = path.join(outDir, assetPath);
    fs.mkdirSync(path.dirname(assetTarget), { recursive: true });
    fs.copyFileSync(sourcePath, assetTarget);
    const content = readTextIfPossible(sourcePath);
    const contentId = sha256File(sourcePath);

    nodes.push({
      id: nodeId,
      title: titleFor(relativePath),
      type: kind.type,
      subtype: kind.subtype,
      importance:
        relativePath === "README.md" ||
        relativePath === "hugo.yaml" ||
        relativePath === "theme.toml" ||
        relativePath.startsWith("layouts/") ||
        relativePath.startsWith("tools/") ||
        relativePath.startsWith("exampleSite/")
          ? 4
          : 3,
      summary: summaryFor(relativePath, kind),
      source_url: sourceUrl(relativePath),
      artifact_path: relativePath,
      asset_path: assetPath,
      asset_role: "repository_source",
      media_type: kind.media_type,
      mime_type: kind.mime_type,
      rights_status: "Apache-2.0",
      content_id: contentId,
      ...(content ? { content } : {}),
      source_snapshot: {
        captured_at: generatedAt,
        source_url: sourceUrl(relativePath),
        method: "archive",
        content_id: contentId,
        rights_status: "Apache-2.0",
        tool: "xananode-hugo/tools/build-substrate-source.mjs"
      },
      relationships: []
    });

    relationships.push({
      id: `xananode.hugo:rel/repository-contains-${localSlug}`,
      source: "xananode.hugo:source/repository-xananode-hugo",
      target: nodeId,
      type: "contains",
      summary: `The Hugo repository contains ${relativePath}.`,
      asserted_at: generatedAt
    });

    if (relativePath.startsWith("layouts/") || relativePath.startsWith("tools/") || relativePath.startsWith("assets/") || relativePath.startsWith("static/")) {
      relationships.push({
        id: `xananode.hugo:rel/${localSlug}-supports-hugo-project`,
        source: nodeId,
        target: "xananode.hugo:project/xananode-hugo-theme",
        type: "supports",
        summary: `${titleFor(relativePath)} supports the Hugo projection layer.`,
        asserted_at: generatedAt
      });
    } else if (relativePath.startsWith("exampleSite/")) {
      relationships.push({
        id: `xananode.hugo:rel/${localSlug}-demonstrates-hugo-project`,
        source: nodeId,
        target: "xananode.hugo:project/xananode-hugo-theme",
        type: "demonstrates",
        summary: `${titleFor(relativePath)} demonstrates how the Hugo projection layer is used.`,
        asserted_at: generatedAt
      });
    }
  }

  writeJson(path.join(outDir, "substrate.json"), manifest);
  writeJson(path.join(outDir, "nodes.json"), { nodes });
  writeJson(path.join(outDir, "relationships.json"), { relationships });
  for (const node of nodes) {
    writeJson(path.join(outDir, "nodes", `${node.type}_${slug(node.title)}.json`), node);
  }
  writeText(path.join(outDir, "README.md"), `# XanaNode Hugo Theme Substrate

This folder is the explicit substrate source generated from the XanaNode Hugo repository.

It exists so higher layers can federate with Hugo as a normal substrate instead of inferring Hugo facts ad hoc.

Regenerate it from the repository root with:

\`\`\`powershell
node tools/build-substrate-source.mjs
\`\`\`

Or from \`XanaNode-Master\`:

\`\`\`powershell
npm run hugo:build-substrate-source
\`\`\`
`);

  return {
    outDir,
    manifest,
    nodeCount: nodes.length,
    relationshipCount: relationships.length
  };
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = buildHugoSubstrateSource();
  console.log(`Hugo substrate source: ${result.outDir}`);
  console.log(`  Nodes: ${result.nodeCount}`);
  console.log(`  Relationships: ${result.relationshipCount}`);
}

#!/usr/bin/env node
import fs from "node:fs";
import path from "node:path";
import process from "node:process";
import { createHash } from "node:crypto";
import matter from "gray-matter";
import { globSync } from "glob";
import Ajv2020 from "ajv/dist/2020.js";
import {
  analyzeSubstrateIntake,
  buildFragments as buildCoreFragments,
  findXanaReferences,
  loadSubstratePack,
  packReferenceForManifest,
  parseXanaRef as parseCoreXanaRef,
  rangeToText as coreRangeToText,
  resolveSubstratePacks,
  validateSubstrateArtifacts as validateCoreSubstrateArtifacts
} from "@xananode/core";

const siteRoot = path.resolve(process.argv[2] || ".");
const themeRootCandidates = [
  path.join(siteRoot, "themes", "xananode-hugo"),
  path.join(siteRoot, "themes", "xananode"),
  path.join(siteRoot, "..", "xananode-hugo"),
  path.join(siteRoot, "..", "xananode"),
  path.resolve(siteRoot, ".."),
  siteRoot
];
const themeRoot = themeRootCandidates.find((candidate) => fs.existsSync(path.join(candidate, "static", "schemas"))) || themeRootCandidates[0];
const sdkRootCandidates = [
  process.env.XANANODE_SDK_ROOT,
  path.resolve(themeRoot, "vendor", "xananode-core"),
  path.resolve(siteRoot, "..", "..", "..", "..", "XanaNode-Core-SDK"),
  path.resolve(siteRoot, "..", "..", "..", "..", "xananode-core-sdk"),
  path.resolve(themeRoot, "..", "..", "..", "XanaNode-Core-SDK"),
  path.resolve(themeRoot, "..", "..", "..", "xananode-core-sdk")
].filter(Boolean);
const schemaCandidates = [
  ...sdkRootCandidates.map((candidate) => path.join(candidate, "schemas")),
  path.join(siteRoot, "static", "schemas"),
  path.join(themeRoot, "static", "schemas")
];
const errors = [];
const warnings = [];
const protocolSchemaNames = [
  "substrate-manifest.schema.json",
  "substrate-node.schema.json",
  "substrate-relationships.schema.json"
];
const schemaAliasPairs = [
  ["xananode-node-types.v0.3.0.json", "xananode-node-types.json"],
  ["xananode-node-types.schema.v0.3.0.json", "xananode-node-types.schema.json"],
  ["xananode-relationship-types.v0.4.0.json", "xananode-relationship-types.json"],
  ["xananode-relationship-types.schema.v0.4.0.json", "xananode-relationship-types.schema.json"],
  ["xananode-relationship-types.v0.5.0.json", "xananode-relationship-types.json"],
  ["xananode-relationship-types.schema.v0.5.0.json", "xananode-relationship-types.schema.json"]
];

function firstExistingFile(relativePath) {
  for (const dir of schemaCandidates) {
    const candidate = path.join(dir, relativePath);
    if (fs.existsSync(candidate)) return candidate;
  }
  return null;
}

function parseSemver(version) {
  const match = String(version || "").trim().replace(/^v/, "").match(/^(\d+)\.(\d+)\.(\d+)(?:[-+].*)?$/);
  if (!match) return null;
  return match.slice(1).map(Number);
}

function compareSemver(left, right) {
  if (!left && !right) return 0;
  if (!left) return -1;
  if (!right) return 1;
  for (let index = 0; index < 3; index += 1) {
    const diff = left[index] - right[index];
    if (diff) return diff;
  }
  return 0;
}

function resolveMostRecentJson(baseName) {
  const candidates = [];
  const pattern = new RegExp(`^${baseName.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}(?:\\.v(\\d+\\.\\d+\\.\\d+))?\\.json$`);

  for (const dir of schemaCandidates) {
    if (!fs.existsSync(dir)) continue;
    for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
      if (!entry.isFile()) continue;
      const match = entry.name.match(pattern);
      if (!match) continue;
      candidates.push({
        filePath: path.join(dir, entry.name),
        version: parseSemver(match[1])
      });
    }
  }

  candidates.sort((left, right) => {
    const versionDiff = compareSemver(left.version, right.version);
    if (versionDiff !== 0) return versionDiff;
    return left.filePath.localeCompare(right.filePath);
  });

  return candidates.at(-1)?.filePath || null;
}

function readJson(filePath) {
  return JSON.parse(fs.readFileSync(filePath, "utf8"));
}

function isPlainObject(value) {
  return value !== null && typeof value === "object" && !Array.isArray(value);
}

function withoutGeneratedAt(value) {
  return JSON.stringify(value, (key, innerValue) => key === "generated_at" ? undefined : innerValue);
}

function withStableGeneratedAt(nextValue, existingPath) {
  if (!fs.existsSync(existingPath)) return nextValue;
  try {
    const existingValue = readJson(existingPath);
    if (withoutGeneratedAt(existingValue) === withoutGeneratedAt(nextValue) && existingValue.generated_at) {
      return { ...nextValue, generated_at: existingValue.generated_at };
    }
  } catch {
    // Keep the fresh timestamp if the previous artifact cannot be read.
  }
  return nextValue;
}

function asArray(value) {
  if (value === undefined || value === null) return [];
  return Array.isArray(value) ? value : [value];
}

function slugify(value, fallback = "item") {
  const slug = String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, "-")
    .replace(/^-+|-+$/g, "");
  return slug || fallback;
}

function protocolTypePath(type) {
  const normalizedType = slugify(type, "node");
  if (normalizedType === "person") return "person";
  if (normalizedType === "media") return "media";
  return normalizedType;
}

const PUBLIC_ROUTE_TYPES = new Set([
  "claim",
  "concept",
  "essay",
  "media",
  "observation",
  "person",
  "project",
  "schema",
  "source",
  "technology",
  "trail",
  "node"
]);

function nodeIdFor(relativeFile, data) {
  return data.node_id || path.basename(relativeFile, ".md");
}

function protocolIdFor(localId, data, namespace) {
  if (data.protocol_id) return data.protocol_id;
  if (String(localId).includes(":")) return String(localId);
  return `${namespace}:${protocolTypePath(data.type)}/${slugify(localId, "node")}`;
}

function contentIdFor(value) {
  return `sha256:${createHash("sha256").update(String(value || "")).digest("hex")}`;
}

function relationshipIdFor(namespace, sourceId, relationshipType, targetId, index) {
  const sourceSlug = slugify(sourceId.split("/").at(-1), "source");
  const targetSlug = slugify(targetId.split("/").at(-1), "target");
  return `${namespace}:rel/${sourceSlug}-${slugify(relationshipType, "related-to")}-${targetSlug}-${index + 1}`;
}

function generatedSummary(edge) {
  return `${edge.sourceTitle || edge.source} ${String(edge.type || "related_to").replaceAll("_", " ")} ${edge.targetTitle || edge.target}.`;
}

function escapeHtml(value) {
  return String(value || "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

const CRC32_TABLE = new Uint32Array(256);
for (let index = 0; index < CRC32_TABLE.length; index += 1) {
  let crc = index;
  for (let bit = 0; bit < 8; bit += 1) {
    crc = (crc & 1) ? (0xedb88320 ^ (crc >>> 1)) : (crc >>> 1);
  }
  CRC32_TABLE[index] = crc >>> 0;
}

function crc32(buffer) {
  let crc = 0xffffffff;
  for (const byte of buffer) {
    crc = CRC32_TABLE[(crc ^ byte) & 0xff] ^ (crc >>> 8);
  }
  return (crc ^ 0xffffffff) >>> 0;
}

function dosDateTime(date = new Date()) {
  const year = Math.max(1980, date.getFullYear());
  const time = ((date.getHours() & 0x1f) << 11)
    | ((date.getMinutes() & 0x3f) << 5)
    | ((Math.floor(date.getSeconds() / 2)) & 0x1f);
  const dosDate = (((year - 1980) & 0x7f) << 9)
    | (((date.getMonth() + 1) & 0x0f) << 5)
    | (date.getDate() & 0x1f);
  return { time, date: dosDate };
}

function createStoredZip(entries = []) {
  const localParts = [];
  const centralParts = [];
  let offset = 0;
  const { time, date } = dosDateTime();

  for (const entry of entries) {
    const name = String(entry.name || "").replaceAll("\\", "/").replace(/^\/+/, "");
    if (!name) continue;
    const data = Buffer.isBuffer(entry.data) ? entry.data : Buffer.from(entry.data || "");
    const nameBuffer = Buffer.from(name, "utf8");
    const crc = crc32(data);
    const localHeader = Buffer.alloc(30);
    localHeader.writeUInt32LE(0x04034b50, 0);
    localHeader.writeUInt16LE(20, 4);
    localHeader.writeUInt16LE(0, 6);
    localHeader.writeUInt16LE(0, 8);
    localHeader.writeUInt16LE(time, 10);
    localHeader.writeUInt16LE(date, 12);
    localHeader.writeUInt32LE(crc, 14);
    localHeader.writeUInt32LE(data.length, 18);
    localHeader.writeUInt32LE(data.length, 22);
    localHeader.writeUInt16LE(nameBuffer.length, 26);
    localHeader.writeUInt16LE(0, 28);
    localParts.push(localHeader, nameBuffer, data);

    const centralHeader = Buffer.alloc(46);
    centralHeader.writeUInt32LE(0x02014b50, 0);
    centralHeader.writeUInt16LE(20, 4);
    centralHeader.writeUInt16LE(20, 6);
    centralHeader.writeUInt16LE(0, 8);
    centralHeader.writeUInt16LE(0, 10);
    centralHeader.writeUInt16LE(time, 12);
    centralHeader.writeUInt16LE(date, 14);
    centralHeader.writeUInt32LE(crc, 16);
    centralHeader.writeUInt32LE(data.length, 20);
    centralHeader.writeUInt32LE(data.length, 24);
    centralHeader.writeUInt16LE(nameBuffer.length, 28);
    centralHeader.writeUInt16LE(0, 30);
    centralHeader.writeUInt16LE(0, 32);
    centralHeader.writeUInt16LE(0, 34);
    centralHeader.writeUInt16LE(0, 36);
    centralHeader.writeUInt32LE(0, 38);
    centralHeader.writeUInt32LE(offset, 42);
    centralParts.push(centralHeader, nameBuffer);

    offset += localHeader.length + nameBuffer.length + data.length;
  }

  const centralDirectory = Buffer.concat(centralParts);
  const endRecord = Buffer.alloc(22);
  endRecord.writeUInt32LE(0x06054b50, 0);
  endRecord.writeUInt16LE(0, 4);
  endRecord.writeUInt16LE(0, 6);
  const entryCount = entries.filter((entry) => String(entry?.name || "").trim()).length;
  endRecord.writeUInt16LE(entryCount, 8);
  endRecord.writeUInt16LE(entryCount, 10);
  endRecord.writeUInt32LE(centralDirectory.length, 12);
  endRecord.writeUInt32LE(offset, 16);
  endRecord.writeUInt16LE(0, 20);

  return Buffer.concat([...localParts, centralDirectory, endRecord]);
}

function readFileIfExists(filePath) {
  if (!fs.existsSync(filePath) || !fs.statSync(filePath).isFile()) return null;
  return fs.readFileSync(filePath);
}

function collectPortableSubstrateEntries({ siteRoot, staticDir, dataDir, includeViewerArtifacts = false } = {}) {
  const entries = [];
  const projectionAssetExtensions = new Set([".css", ".scss", ".sass", ".js", ".mjs", ".cjs", ".ts", ".tsx", ".jsx", ".map", ".html", ".htm", ".xml"]);
  const isProjectionAsset = (relativeFile) => projectionAssetExtensions.has(path.extname(relativeFile).toLowerCase());
  const addFile = (sourcePath, archivePath) => {
    const buffer = readFileIfExists(sourcePath);
    if (buffer) entries.push({ name: archivePath, data: buffer });
  };
  const addTree = (sourceRoot, archiveRoot, filter = () => true) => {
    if (!sourceRoot || !fs.existsSync(sourceRoot) || !fs.statSync(sourceRoot).isDirectory()) return;
    const files = globSync("**/*", { cwd: sourceRoot, nodir: true });
    for (const relativeFile of files) {
      if (!filter(relativeFile)) continue;
      const sourcePath = path.join(sourceRoot, relativeFile);
      const archivePath = path.posix.join(archiveRoot, relativeFile.split(path.sep).join("/"));
      addFile(sourcePath, archivePath);
    }
  };

  addFile(path.join(staticDir, "substrate.json"), "substrate.json");
  addFile(path.join(staticDir, "nodes-index.json"), "nodes-index.json");
  addFile(path.join(staticDir, "relationships.json"), "relationships.json");
  addFile(path.join(staticDir, "substrate-bundle.json"), "substrate-bundle.json");
  addFile(path.join(staticDir, "substrate-bundle.jsonl"), "substrate-bundle.jsonl");
  addFile(path.join(staticDir, "xananode-fragments.json"), "xananode-fragments.json");
  addFile(path.join(staticDir, "xananode-suggestions.json"), "xananode-suggestions.json");
  if (includeViewerArtifacts) {
    addFile(path.join(staticDir, "xananode-viewer.json"), "xananode-viewer.json");
    addFile(path.join(staticDir, "xananode-suggestions.md"), "xananode-suggestions.md");
  }
  addTree(path.join(staticDir, "nodes"), "nodes");
  addTree(path.join(staticDir, "schemas"), "schemas");
  addTree(path.join(siteRoot, "assets"), "assets", (relativeFile) => !isProjectionAsset(relativeFile));
  addTree(path.join(siteRoot, "reports"), "reports");
  addTree(path.join(siteRoot, "packs"), "packs");
  addTree(path.join(siteRoot, "imports"), "imports");
  addFile(path.join(siteRoot, "author-profile.json"), "author-profile.json");
  addFile(path.join(siteRoot, "ro-crate-metadata.json"), "ro-crate-metadata.json");

  return entries;
}

function configuredDownloadSubstrate() {
  const text = readSiteConfigText();
  const lines = text.split(/\r?\n/);
  const defaultPath = `archives/${substrateNamespace}.substrate`;
  const config = {
    enabled: false,
    label: "Download current substrate",
    path: defaultPath,
    includeViewerArtifacts: false
  };

  const directMatch = lines.find((line) => /^\s{4}downloadSubstrate:\s*(.+)$/.test(line));
  if (directMatch) {
    const match = directMatch.match(/^\s{4}downloadSubstrate:\s*(.+)$/);
    const directValue = parseYamlScalar(match?.[1] || "");
    config.enabled = Boolean(directValue);
    return config;
  }

  const blockStart = lines.findIndex((line) => /^\s{4}downloadSubstrate:\s*$/.test(line));
  if (blockStart < 0) return config;

  for (let index = blockStart + 1; index < lines.length; index += 1) {
    const line = lines[index];
    if (/^\S/.test(line)) break;
    const propertyMatch = line.match(/^\s{6}([\w-]+):\s*(.*)$/);
    if (!propertyMatch) continue;
    const key = propertyMatch[1];
    const value = parseYamlScalar(propertyMatch[2]);
    if (key === "enabled") {
      config.enabled = Boolean(value);
    } else if (key === "label") {
      config.label = String(value || config.label);
    } else if (key === "path") {
      config.path = String(value || config.path).replace(/^\/+/, "");
    } else if (key === "includeViewerArtifacts" || key === "include_viewer_artifacts") {
      config.includeViewerArtifacts = Boolean(value);
    }
  }

  return config;
}

function protocolRelationshipRecord(relationship) {
  const {
    imported_from,
    pack_id,
    pack_mode,
    ...record
  } = relationship;
  return record;
}

function readSiteConfigText() {
  for (const fileName of ["hugo.yaml", "hugo.yml", "config.yaml", "config.yml"]) {
    const filePath = path.join(siteRoot, fileName);
    if (fs.existsSync(filePath)) return fs.readFileSync(filePath, "utf8");
  }
  return "";
}

function configuredTopLevelScalar(key) {
  const text = readSiteConfigText();
  const match = text.match(new RegExp(`^${key}:\\s*(.+)$`, "m"));
  return match ? parseYamlScalar(match[1]) : "";
}

function configuredNestedScalar(pathParts) {
  const text = readSiteConfigText();
  const lines = text.split(/\r?\n/);
  let startIndex = 0;
  let baseIndent = 0;

  for (const part of pathParts) {
    const indent = " ".repeat(baseIndent);
    const pattern = new RegExp(`^${indent}${part}:\\s*(.*)$`);
    let foundIndex = -1;
    let foundValue = "";
    for (let index = startIndex; index < lines.length; index += 1) {
      const line = lines[index];
      const match = line.match(pattern);
      if (match) {
        foundIndex = index;
        foundValue = match[1];
        break;
      }
      if (index > startIndex && line.trim() && !line.startsWith(indent + " ")) break;
    }
    if (foundIndex < 0) return "";
    if (part === pathParts.at(-1)) return parseYamlScalar(foundValue);
    startIndex = foundIndex + 1;
    baseIndent += 2;
  }

  return "";
}

function configuredPackReferences() {
  const text = readSiteConfigText();
  const lines = text.split(/\r?\n/);
  const packsLine = lines.findIndex((line) => /^\s{4}packs:\s*$/.test(line));
  if (packsLine < 0) return [];
  const packs = [];
  let current = null;
  let currentNamespaceMapping = null;
  for (let index = packsLine + 1; index < lines.length; index += 1) {
    const line = lines[index];
    if (/^\S/.test(line)) break;
    const itemMatch = line.match(/^\s{6}-\s*(?:(\w+):\s*(.*))?$/);
    if (itemMatch) {
      if (current) packs.push(current);
      current = {};
      currentNamespaceMapping = null;
      if (itemMatch[1]) current[itemMatch[1]] = parseYamlScalar(itemMatch[2]);
      continue;
    }
    const mappingItemMatch = line.match(/^\s{10}-\s*(?:(\w+):\s*(.*))?$/);
    if (current && Array.isArray(current.namespace_mappings) && mappingItemMatch) {
      currentNamespaceMapping = {};
      current.namespace_mappings.push(currentNamespaceMapping);
      if (mappingItemMatch[1]) currentNamespaceMapping[mappingItemMatch[1]] = parseYamlScalar(mappingItemMatch[2]);
      continue;
    }
    const mappingPropertyMatch = line.match(/^\s{12}(\w+):\s*(.*)$/);
    if (currentNamespaceMapping && mappingPropertyMatch) {
      currentNamespaceMapping[mappingPropertyMatch[1]] = parseYamlScalar(mappingPropertyMatch[2]);
      continue;
    }
    const propertyMatch = line.match(/^\s{8}(\w+):\s*(.*)$/);
    if (current && propertyMatch) {
      currentNamespaceMapping = null;
      current[propertyMatch[1]] = propertyMatch[1] === "namespace_mappings" ? [] : parseYamlScalar(propertyMatch[2]);
    } else if (/^\s{0,5}\S/.test(line)) {
      break;
    }
  }
  if (current) packs.push(current);
  return packs.filter((pack) => pack.source && pack.enabled !== false);
}

function parseYamlScalar(value) {
  const text = String(value || "").trim().replace(/^["']|["']$/g, "");
  if (text === "true") return true;
  if (text === "false") return false;
  return text;
}

function configuredThemeLinks() {
  const text = readSiteConfigText();
  const lines = text.split(/\r?\n/);
  const linksLine = lines.findIndex((line) => /^\s{4}links:\s*$/.test(line));
  if (linksLine < 0) return [];

  const links = [];
  let current = null;
  for (let index = linksLine + 1; index < lines.length; index += 1) {
    const line = lines[index];
    if (/^\S/.test(line)) break;
    const itemMatch = line.match(/^\s{6}-\s*(?:(\w+):\s*(.*))?$/);
    if (itemMatch) {
      if (current) links.push(current);
      current = {};
      if (itemMatch[1]) current[itemMatch[1]] = parseYamlScalar(itemMatch[2]);
      continue;
    }
    const propertyMatch = line.match(/^\s{8}(\w+):\s*(.*)$/);
    if (current && propertyMatch) {
      current[propertyMatch[1]] = parseYamlScalar(propertyMatch[2]);
    } else if (/^\s{0,5}\S/.test(line)) {
      break;
    }
  }
  if (current) links.push(current);
  return links.filter((link) => link && link.label && link.url);
}

function trimTrailingSlash(value) {
  return String(value || "").replace(/\/+$/, "");
}

function joinAbsoluteUrl(base, relativePath) {
  const normalizedBase = trimTrailingSlash(base);
  const normalizedPath = String(relativePath || "").replace(/^\/+/, "");
  if (!normalizedBase) return `/${normalizedPath}`;
  return `${normalizedBase}/${normalizedPath}`;
}

function localImportPackReferences() {
  const roots = ["imports", "data/imports", "data/xananode-imports"];
  const packs = [];
  for (const root of roots) {
    const fullRoot = path.join(siteRoot, root);
    if (!fs.existsSync(fullRoot)) continue;
    const entries = fs.readdirSync(fullRoot, { withFileTypes: true });
    if (entries.some((entry) => entry.isFile() && entry.name.endsWith(".json"))) {
      packs.push({ id: root.replace(/\//g, ":"), source: root, mode: "mounted" });
    }
    for (const entry of entries) {
      if (entry.isDirectory()) {
        const source = path.join(root, entry.name).replace(/\\/g, "/");
        packs.push({ id: source.replace(/\//g, ":"), source, mode: "mounted" });
      }
    }
  }
  return packs;
}

function collectImportedProtocolArtifacts() {
  const configured = resolveSubstratePacks(configuredPackReferences(), {
    baseDir: siteRoot,
    extraBaseDirs: [themeRoot],
    receivingNamespace: substrateNamespace
  });
  const localPacks = localImportPackReferences().map((pack) => loadSubstratePack(path.resolve(siteRoot, pack.source), {
    pack,
    receivingNamespace: substrateNamespace
  }));
  const allPacks = [...configured.packs, ...localPacks];
  const importedNodes = [];
  const importedRelationships = [];

  for (const pack of allPacks) {
    importedNodes.push(...pack.nodes);
    importedRelationships.push(...pack.relationships);
    for (const warning of pack.warnings || []) warnings.push(`Pack ${pack.pack?.id || pack.root}: ${JSON.stringify(warning)}`);
    for (const error of pack.errors || []) errors.push(`Pack ${pack.pack?.id || pack.root}: ${JSON.stringify(error)}`);
  }
  for (const warning of configured.warnings || []) warnings.push(`Pack import: ${JSON.stringify(warning)}`);
  for (const error of configured.errors || []) errors.push(`Pack import: ${JSON.stringify(error)}`);

  return {
    importedNodes,
    importedRelationships,
    importedPacks: allPacks.map((pack) => packReferenceForManifest(pack.pack)).filter(Boolean)
  };
}

function copyProtocolSchemas(staticSchemaDir) {
  fs.mkdirSync(staticSchemaDir, { recursive: true });
  for (const schemaName of protocolSchemaNames) {
    const source = firstExistingFile(schemaName);
    if (source) {
      fs.copyFileSync(source, path.join(staticSchemaDir, schemaName));
    }
  }
  for (const [versionedName, aliasName] of schemaAliasPairs) {
    const source = firstExistingFile(versionedName);
    if (source) {
      fs.copyFileSync(source, path.join(staticSchemaDir, versionedName));
      fs.copyFileSync(source, path.join(staticSchemaDir, aliasName));
    }
  }
}

function copyProtocolBrandAssets(staticDir) {
  const protocolMediaRoot = sdkRootCandidates
    .map((candidate) => path.join(candidate, "vendor", "xananode-protocol", "media"))
    .find((candidate) => fs.existsSync(candidate));
  if (!protocolMediaRoot) return;
  const brandAssets = [
    ["images", "xananode-icon.svg", "xananode-icon.svg"],
    ["images", "favicon.ico", "favicon.ico"],
    ["images", "favicon-32x32.png", "favicon-32x32.png"],
    ["images", "favicon-16x16.png", "favicon-16x16.png"],
    ["images", "apple-touch-icon.png", "apple-touch-icon.png"],
    ["images", "android-chrome-192x192.png", "android-chrome-192x192.png"],
    ["images", "android-chrome-512x512.png", "android-chrome-512x512.png"],
    ["web-manifests", "site.webmanifest", "site.webmanifest"]
  ];

  for (const [folder, filename, targetName] of brandAssets) {
    const source = path.join(protocolMediaRoot, folder, filename);
    if (fs.existsSync(source)) {
      fs.copyFileSync(source, path.join(staticDir, targetName));
    }
  }
}

function copyProtocolProjectionAssets(staticDir) {
  const protocolMediaRoot = sdkRootCandidates
    .map((candidate) => path.join(candidate, "vendor", "xananode-protocol", "media"))
    .find((candidate) => fs.existsSync(candidate));
  if (!protocolMediaRoot) return;
  const source = path.join(protocolMediaRoot, "projection");
  if (!fs.existsSync(source)) return;
  const target = path.join(staticDir, "assets", "projection");
  fs.mkdirSync(path.dirname(target), { recursive: true });
  fs.cpSync(source, target, { recursive: true });
}

function writeDiscoveryArtifacts(staticDir, substrateManifest) {
  const downloadConfig = configuredDownloadSubstrate();
  const configuredBaseUrl = process.env.XANANODE_BASE_URL
    || configuredTopLevelScalar("baseURL")
    || process.env.URL
    || "";
  const configuredNamespace = process.env.XANANODE_NAMESPACE
    || configuredNestedScalar(["params", "xananode", "namespace"])
    || substrateManifest.namespace;
  const configuredTitle = process.env.XANANODE_NAME
    || configuredTopLevelScalar("title")
    || substrateManifest.name;
  const viewerUrl = joinAbsoluteUrl(configuredBaseUrl, "");
  const substrateUrl = joinAbsoluteUrl(configuredBaseUrl, "substrate.json");
  const relationshipsUrl = joinAbsoluteUrl(configuredBaseUrl, "relationships.json");
  const nodesIndexUrl = joinAbsoluteUrl(configuredBaseUrl, "nodes-index.json");
  const schemasUrl = joinAbsoluteUrl(configuredBaseUrl, "schemas/");
  const viewerFeedUrl = joinAbsoluteUrl(configuredBaseUrl, "xananode-viewer.json");
  const legacyIndexUrl = joinAbsoluteUrl(configuredBaseUrl, "index.json");
  const downloadArchiveUrl = downloadConfig.enabled
    ? joinAbsoluteUrl(configuredBaseUrl, downloadConfig.path)
    : "";
  const wellKnownDir = path.join(staticDir, ".well-known");
  fs.mkdirSync(wellKnownDir, { recursive: true });

  const handshake = {
    protocol: "xananode",
    title: configuredTitle,
    namespace: configuredNamespace,
    substrate: substrateUrl,
    relationships: relationshipsUrl,
    nodes_index: nodesIndexUrl,
    schemas: schemasUrl,
    viewer: viewerUrl,
    viewer_feed: viewerFeedUrl,
    legacy_viewer_index: legacyIndexUrl,
    ...(downloadArchiveUrl ? { substrate_archive: downloadArchiveUrl } : {})
  };

  fs.writeFileSync(path.join(wellKnownDir, "xananode"), JSON.stringify(handshake, null, 2) + "\n");
  fs.writeFileSync(path.join(wellKnownDir, "xananode.json"), JSON.stringify(handshake, null, 2) + "\n");

  const robots = [
    "User-agent: *",
    "Allow: /",
    "",
    `Sitemap: ${joinAbsoluteUrl(configuredBaseUrl, "sitemap.xml")}`,
    `XanaNode-Well-Known: ${joinAbsoluteUrl(configuredBaseUrl, ".well-known/xananode")}`,
    `XanaNode-Substrate: ${substrateUrl}`,
    `XanaNode-Nodes-Index: ${nodesIndexUrl}`,
    `XanaNode-Relationships: ${relationshipsUrl}`,
    `XanaNode-Viewer: ${viewerFeedUrl}`,
    ...(downloadArchiveUrl ? [`XanaNode-Substrate-Archive: ${downloadArchiveUrl}`] : [])
  ].join("\n");

  fs.writeFileSync(path.join(staticDir, "robots.txt"), `${robots}\n`);
}

function stripMarkdown(markdown) {
  return markdown
    .replace(/```[\s\S]*?```/g, "")
    .replace(/`([^`]+)`/g, "$1")
    .replace(/!\[[^\]]*\]\([^)]*\)/g, "")
    .replace(/\[([^\]]+)\]\([^)]*\)/g, "$1")
    .replace(/^#{1,6}\s+/gm, "")
    .replace(/^>\s?/gm, "")
    .replace(/^[-*+]\s+/gm, "")
    .replace(/^\d+\.\s+/gm, "")
    .trim();
}

function fragmentProtocolIdFor(namespace, sourceId, fragmentId) {
  return `${namespace}:fragment/${slugify(sourceId, "node")}-${slugify(fragmentId, "fragment")}`;
}

function normalizeAuthoredFragments(data) {
  return asArray(data.fragments).filter(Boolean);
}

function buildFragments(markdown, data, context) {
  const coreFragments = buildCoreFragments(markdown, data, {
    namespace: context.namespace,
    sourceId: context.localId,
    sourceProtocolId: context.protocolId,
    sourceContentId: context.sourceContentId,
    sourceVersionId: context.sourceVersionId
  });
  const fragmentMap = {};
  for (const fragment of coreFragments.generated) {
    fragmentMap[fragment.id] = fragment.text;
  }
  if (coreFragments.generated.length) {
    fragmentMap["1"] = coreFragments.generated.map((fragment) => fragment.text).filter(Boolean).join("\n\n");
  }
  const metadata = {};
  const seenAuthoredIds = new Set();

  for (const [index, fragment] of normalizeAuthoredFragments(data).entries()) {
    if (!fragment || typeof fragment !== "object") {
      errors.push(`${context.file}: fragments[${index}] must be an object.`);
      continue;
    }

    const fragmentId = String(fragment.id || fragment.fragment_id || "").trim();
    if (!fragmentId) {
      errors.push(`${context.file}: fragments[${index}] is missing "id".`);
      continue;
    }
    if (!/^[A-Za-z0-9._-]+$/.test(fragmentId)) {
      errors.push(`${context.file}: fragment id "${fragmentId}" must use only letters, numbers, dots, underscores, or hyphens.`);
      continue;
    }
    if (seenAuthoredIds.has(fragmentId)) {
      errors.push(`${context.file}: duplicate authored fragment id "${fragmentId}".`);
      continue;
    }
    seenAuthoredIds.add(fragmentId);

    const text = String(fragment.text || fragment.content || "").replace(/\s+/g, " ").trim();
    if (!text) {
      errors.push(`${context.file}: fragment "${fragmentId}" is missing "text".`);
      continue;
    }

    const protocolId = fragment.protocol_id || fragmentProtocolIdFor(context.namespace, context.localId, fragmentId);
    const sourceContentId = context.sourceContentId;
    const sourceVersionId = context.sourceVersionId;
    const fragmentContentId = fragment.content_id || contentIdFor(fragment.raw || text || fragmentId);
    const fragmentVersionId = fragment.version_id || fragmentContentId;
    const tumbler = fragment.tumbler || `${context.protocolId}@${sourceVersionId}#fragment/${fragmentId}@${fragmentVersionId}`;
    fragmentMap[fragmentId] = text;
    metadata[fragmentId] = {
      authored: true,
      id: fragmentId,
      text,
      content_id: fragmentContentId,
      version_id: fragmentVersionId,
      source_content_id: sourceContentId,
      source_version_id: sourceVersionId,
      title: fragment.title || `${data.title || context.localId} Fragment ${fragmentId}`,
      summary: fragment.summary || `A stable addressable fragment of ${data.title || context.localId}.`,
      source_node: context.protocolId,
      protocol_id: protocolId,
      tumbler,
      selector: fragment.selector || { type: "semantic-anchor", value: fragmentId },
      ...(fragment.rights_status || data.rights_status ? { rights_status: fragment.rights_status || data.rights_status } : {})
    };
  }

  return { fragments: fragmentMap, metadata };
}

function parseXanaRef(ref) {
  const parsed = parseCoreXanaRef(ref);
  if (!parsed) return null;
  return {
    nodeId: parsed.node,
    version: parsed.version || "latest",
    range: parsed.range || parsed.start || "1"
  };
}

function rangeToText(fragmentMap, range) {
  const direct = coreRangeToText(fragmentMap, range);
  if (direct) return direct;
  const [start, end] = String(range).split("-");
  if (!start || !end) return null;
  const startParts = start.split(".").map(Number);
  const endParts = end.split(".").map(Number);
  if (startParts.length !== endParts.length) return null;
  const addresses = Object.keys(fragmentMap)
    .filter((address) => address.split(".").length === startParts.length)
    .sort((a, b) => {
      const ap = a.split(".").map(Number);
      const bp = b.split(".").map(Number);
      for (let i = 0; i < Math.max(ap.length, bp.length); i++) {
        const diff = (ap[i] || 0) - (bp[i] || 0);
        if (diff !== 0) return diff;
      }
      return 0;
    });
  const startIndex = addresses.indexOf(start);
  const endIndex = addresses.indexOf(end);
  if (startIndex === -1 || endIndex === -1 || endIndex < startIndex) return null;
  return addresses.slice(startIndex, endIndex + 1).map((address) => fragmentMap[address]).join(" ");
}

function uniqueStrings(values) {
  return [...new Set(values.map((value) => String(value || "").trim()).filter(Boolean))];
}

function nodeAliases(data) {
  return uniqueStrings([
    ...asArray(data.aliases),
    ...asArray(data.alias),
    ...asArray(data.alternate_titles),
    ...asArray(data.alternate_title)
  ]);
}

function escapeRegExp(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function phrasePattern(phrase) {
  return new RegExp(`(?<![\\p{L}\\p{N}_])${escapeRegExp(phrase)}(?![\\p{L}\\p{N}_])`, "iu");
}

function allPhraseMatches(text, phrase) {
  const pattern = new RegExp(`(?<![\\p{L}\\p{N}_])${escapeRegExp(phrase)}(?![\\p{L}\\p{N}_])`, "giu");
  return [...String(text || "").matchAll(pattern)];
}

function rangesFor(pattern, text) {
  return [...String(text || "").matchAll(pattern)].map((match) => [match.index, match.index + match[0].length]);
}

function positionInRanges(index, ranges) {
  return ranges.some(([start, end]) => index >= start && index < end);
}

function markdownProtectedRanges(markdown) {
  const ranges = [
    ...rangesFor(/```[\s\S]*?```/g, markdown),
    ...rangesFor(/`[^`\n]+`/g, markdown),
    ...rangesFor(/!\[[^\]]*]\([^)]*\)/g, markdown),
    ...rangesFor(/\[[^\]]+]\([^)]*\)/g, markdown),
    ...rangesFor(/\{\{[<%][\s\S]*?[>%]\}\}/g, markdown),
    ...rangesFor(/<a\b[\s\S]*?<\/a>/gi, markdown)
  ];
  return ranges.sort((left, right) => left[0] - right[0]);
}

function lineColumnFor(text, index) {
  const before = String(text || "").slice(0, index);
  const lines = before.split(/\r?\n/);
  return {
    line: lines.length,
    column: lines.at(-1).length + 1
  };
}

function linkTargetFor(node) {
  return `/${protocolTypePath(node.data?.type || "node")}/${encodeURIComponent(node.id)}/`;
}

function nodeIdFromLinkHref(href) {
  const value = String(href || "").trim();
  let pathValue = value;
  try {
    pathValue = new URL(value, "https://xananode.local").pathname;
  } catch {
    pathValue = value;
  }
  const stripped = pathValue.replace(/^\//, "").replace(/\/$/, "");
  const [routeType, ...rest] = stripped.split("/");
  if (!PUBLIC_ROUTE_TYPES.has(routeType) || !rest.length) return null;
  try {
    return decodeURIComponent(rest.at(-1));
  } catch {
    return rest.at(-1);
  }
}

function existingLinkedTargetIds(markdown, nodeIds) {
  const linked = new Set();
  for (const match of String(markdown || "").matchAll(/\[[^\]]+]\(([^)\s]+)(?:\s+["'][^"']*["'])?\)/g)) {
    const nodeId = nodeIdFromLinkHref(match[1]);
    if (nodeId && nodeIds.has(nodeId)) linked.add(nodeId);
  }
  return linked;
}

function approvedReplacementNote() {
  return "Suggestion only. Review and apply manually if approved.";
}

function bodyStartLine(raw, body) {
  const index = String(raw || "").indexOf(body || "");
  if (index < 0) return 1;
  return String(raw).slice(0, index).split(/\r?\n/).length;
}

function reportPosition(source, markdown, index) {
  const position = lineColumnFor(markdown, index);
  return {
    line: position.line + (source.body_start_line || 1) - 1,
    column: position.column
  };
}

function shortPreview(value, maxLength = 160) {
  const text = String(value || "").replace(/\s+/g, " ").trim();
  if (text.length <= maxLength) return text;
  return `${text.slice(0, maxLength - 3)}...`;
}

function renderSuggestionReport(suggestions) {
  const lines = [
    "# XanaNode Suggestions",
